package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonArray_whenIsJsonArrayTrue_returnsThisAsJsonArray() {
    // Arrange
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonArray()).thenReturn(true);
    JsonArray jsonArray = mock(JsonArray.class);
    // Cast this mock to JsonArray when getAsJsonArray casts it
    // To simulate that, we need to create a mock that is both JsonElement and JsonArray
    JsonElement jsonArrayElement = mock(JsonArray.class, withSettings().extraInterfaces(JsonElement.class));
    when(jsonArrayElement.isJsonArray()).thenReturn(true);

    // Act
    JsonArray result = (JsonArray) jsonArrayElement.getAsJsonArray();

    // Assert
    assertNotNull(result);
    assertSame(jsonArrayElement, result);
  }

  @Test
  void getAsJsonArray_whenIsJsonArrayFalse_throwsIllegalStateException() {
    // Arrange
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonArray()).thenReturn(false);
    when(jsonElement.toString()).thenReturn("mockedJsonElement");

    // Act & Assert
    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonArray);
    assertEquals("Not a JSON Array: mockedJsonElement", exception.getMessage());
  }
}
